#include <iostream>

using namespace std;

int main() {
    int n;
    cin >> n;
    int max_elevation = -1;
    for (int i = 0; i < n; ++i) {
        int current_elevation;
        cin >> current_elevation;
        if (current_elevation > max_elevation) {
            max_elevation = current_elevation;
        }
    }
    cout << max_elevation << endl;
    return 0;
}

