import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int maxElevation = -1;

        for (int i = 0; i < n; i++) {
            int currentElevation = sc.nextInt();
            if (currentElevation > maxElevation) {
                maxElevation = currentElevation;
            }
        }
        System.out.println(maxElevation);
        sc.close();
    }
}
